import{_ as a,o as l,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"算电协同 · 赛道总览","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"算电协同/赛道总览.md","filePath":"算电协同/赛道总览.md","lastUpdated":1781535932000}'),n={name:"算电协同/赛道总览.md"};function s(i,t,e,o,h,p){return l(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="算电协同-·-赛道总览" tabindex="-1">算电协同 · 赛道总览 <a class="header-anchor" href="#算电协同-·-赛道总览" aria-label="Permalink to &quot;算电协同 · 赛道总览&quot;">​</a></h1><p><strong>定义：</strong> 算电协同（Computing-Electricity Coordination）指通过协调计算负载与电力系统的时空分布，实现算力需求与电力供给的最优匹配。核心目标：<strong>让电等算力，还是算力等电？</strong></p><p><strong>成熟度：</strong> 早期成长期（2025-2026 政策驱动元年） <strong>PE/VC 重心：</strong> 数据中心需求响应、算力调度平台、液冷散热、AI+电力交易</p><hr><h2 id="一、核心逻辑" tabindex="-1">一、核心逻辑 <a class="header-anchor" href="#一、核心逻辑" aria-label="Permalink to &quot;一、核心逻辑&quot;">​</a></h2><h3 id="为什么算电协同现在重要" tabindex="-1">为什么算电协同现在重要？ <a class="header-anchor" href="#为什么算电协同现在重要" aria-label="Permalink to &quot;为什么算电协同现在重要？&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>算力爆发 → 数据中心用电量激增 → 电网承受压力</span></span>
<span class="line"><span>           ↓</span></span>
<span class="line"><span>    算电协同 → 把数据中心从&quot;电老虎&quot;变成&quot;柔性负荷&quot;</span></span>
<span class="line"><span>           ↓</span></span>
<span class="line"><span>    收益：电网减负 × 数据中心降本 × 绿电消纳</span></span></code></pre></div><p><strong>关键数据：</strong></p><ul><li>2026年中国数据中心用电量预计 ~3000亿 kWh，占全社会用电量 ~3.5%</li><li>2025-2030 数据中心用电 CAGR 15-20%（AI 训练+推理驱动）</li><li>单座千P智算中心年用电量 ≈ 3-5 亿 kWh（相当于一个小型工业园）</li><li>数据中心参与需求响应可降低峰值负荷 10-30%</li></ul><h3 id="核心矛盾" tabindex="-1">核心矛盾 <a class="header-anchor" href="#核心矛盾" aria-label="Permalink to &quot;核心矛盾&quot;">​</a></h3><table tabindex="0"><thead><tr><th>矛盾</th><th>说明</th></tr></thead><tbody><tr><td><strong>时间错配</strong></td><td>AI 训练夜间低谷→电价低，推理白天高峰→电价高</td></tr><tr><td><strong>空间错配</strong></td><td>算力集中在东部→电从西部来→输电损耗+通道瓶颈</td></tr><tr><td><strong>利益错配</strong></td><td>电网要稳定、数据中心要低价、政府要碳排——三方博弈</td></tr></tbody></table><hr><h2 id="二、驱动因素" tabindex="-1">二、驱动因素 <a class="header-anchor" href="#二、驱动因素" aria-label="Permalink to &quot;二、驱动因素&quot;">​</a></h2><h3 id="_2-1-政策驱动-最强" tabindex="-1">2.1 政策驱动（最强） <a class="header-anchor" href="#_2-1-政策驱动-最强" aria-label="Permalink to &quot;2.1 政策驱动（最强）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>政策</th><th>时间</th><th>要点</th></tr></thead><tbody><tr><td>算电协同纳入<strong>政府工作报告</strong></td><td>2026</td><td>首次写入国家级规划</td></tr><tr><td>电改 2.0</td><td>2025-2027</td><td>电力现货市场全覆盖，数据中心可参与</td></tr><tr><td>数据中心能效标准 (PUE&lt;1.25)</td><td>2025</td><td>新建数据中心强制要求</td></tr><tr><td>&quot;东数西算&quot;二期</td><td>2025-2028</td><td>算力向西迁移</td></tr><tr><td>新型电力系统建设</td><td>2024-2030</td><td>源网荷储一体化</td></tr></tbody></table><h3 id="_2-2-经济驱动" tabindex="-1">2.2 经济驱动 <a class="header-anchor" href="#_2-2-经济驱动" aria-label="Permalink to &quot;2.2 经济驱动&quot;">​</a></h3><ul><li>数据中心用电成本占运营成本 30-60%</li><li>参与需求响应可降低电费 10-20%</li><li>绿电直购可降低碳成本+品牌溢价</li><li>液冷散热比风冷节能 30-50%（PUE 从1.4→1.1）</li></ul><h3 id="_2-3-技术驱动" tabindex="-1">2.3 技术驱动 <a class="header-anchor" href="#_2-3-技术驱动" aria-label="Permalink to &quot;2.3 技术驱动&quot;">​</a></h3><ul><li>AI 调度算法成熟（DeepSeek/AI Agent 应用于电力调度）</li><li>液冷散热技术商用化（冷板式→浸没式）</li><li>储能成本持续下降（2026年LFP系统成本&lt;0.5元/Wh）</li><li>虚拟电厂技术平台化</li></ul><hr><h2 id="三、产业链全景" tabindex="-1">三、产业链全景 <a class="header-anchor" href="#三、产业链全景" aria-label="Permalink to &quot;三、产业链全景&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>上游（设备/基础设施）         中游（平台/运营）          下游（应用/服务）</span></span>
<span class="line"><span>┌─────────────────┐    ┌──────────────────┐    ┌──────────────────┐</span></span>
<span class="line"><span>│ 液冷散热系统     │    │ 算力调度平台      │    │ 数据中心运营商    │</span></span>
<span class="line"><span>│ 高效UPS/电源     │    │ 电力交易AI平台    │    │ AI算力服务商      │</span></span>
<span class="line"><span>│ 储能系统         │ →  │ 虚拟电厂聚合平台   │ →  │ 云服务/IDC        │</span></span>
<span class="line"><span>│ 智能配电设备     │    │ 碳管理SaaS       │    │ 产业园区/政府     │</span></span>
<span class="line"><span>│ 算力芯片(低功耗)  │    │ 需求响应平台      │    │                    │</span></span>
<span class="line"><span>└─────────────────┘    └──────────────────┘    └──────────────────┘</span></span></code></pre></div><h3 id="关键环节-pe-vc-机会" tabindex="-1">关键环节 PE/VC 机会： <a class="header-anchor" href="#关键环节-pe-vc-机会" aria-label="Permalink to &quot;关键环节 PE/VC 机会：&quot;">​</a></h3><table tabindex="0"><thead><tr><th>环节</th><th>机会</th><th>壁垒</th><th>投资时机</th></tr></thead><tbody><tr><td>液冷散热</td><td>冷板式已商用，浸没式早期</td><td>客户验证+规模</td><td>✅ 现在</td></tr><tr><td>算力调度平台</td><td>跨区域/跨云算力调度</td><td>网络效应</td><td>✅ 现在</td></tr><tr><td>AI电力交易</td><td>现货市场报价策略</td><td>算法+数据</td><td>✅ 窗口期</td></tr><tr><td>VPP聚合数据中心</td><td>数据中心参与需求响应</td><td>客户关系</td><td>✅ 早期</td></tr><tr><td>低功耗算力芯片</td><td>推理场景专用芯片</td><td>流片+生态</td><td>⭐⭐⭐</td></tr></tbody></table><hr><h2 id="四、六大赛道详解" tabindex="-1">四、六大赛道详解 <a class="header-anchor" href="#四、六大赛道详解" aria-label="Permalink to &quot;四、六大赛道详解&quot;">​</a></h2><h3 id="_4-1-数据中心-需求响应-最快落地" tabindex="-1">4.1 数据中心 + 需求响应（最快落地） <a class="header-anchor" href="#_4-1-数据中心-需求响应-最快落地" aria-label="Permalink to &quot;4.1 数据中心 + 需求响应（最快落地）&quot;">​</a></h3><p><strong>逻辑：</strong> 数据中心作为柔性负荷参与电力需求响应市场</p><p><strong>模式：</strong></p><ul><li>削峰：电价高时降低算力负载（训练任务可中断/迁移）</li><li>填谷：电价低时增加算力负载（批量训练/数据备份）</li><li>调频：秒级响应电网频率波动</li></ul><p><strong>代表事件：</strong></p><ul><li>2025年内蒙古首批数据中心参与调峰辅助服务市场</li><li>2026年长三角启动数据中心虚拟电厂试点</li></ul><p><strong>标的：</strong> 光环新网、数据港、秦淮数据、万国数据</p><h3 id="_4-2-算力西迁-绿电消纳" tabindex="-1">4.2 算力西迁 + 绿电消纳 <a class="header-anchor" href="#_4-2-算力西迁-绿电消纳" aria-label="Permalink to &quot;4.2 算力西迁 + 绿电消纳&quot;">​</a></h3><p><strong>逻辑：</strong> 把算力中心建在新能源富集区（西部），就地消纳绿电</p><p><strong>模式：</strong></p><ul><li>源网荷储一体化：风电/光伏 + 储能 + 算力中心</li><li>绿电直购：数据中心直接与新能源场站签PPA</li></ul><p><strong>挑战：</strong></p><ul><li>网络延迟（推理场景受影响）</li><li>人才配套（西部运维人才短缺）</li><li>水资源（西部缺水，液冷需水量大）</li></ul><h3 id="_4-3-ai-电力调度" tabindex="-1">4.3 AI + 电力调度 <a class="header-anchor" href="#_4-3-ai-电力调度" aria-label="Permalink to &quot;4.3 AI + 电力调度&quot;">​</a></h3><p><strong>逻辑：</strong> AI Agent 自主优化电力系统调度</p><p><strong>方向：</strong></p><ul><li>新能源出力预测（风光+负荷）</li><li>现货市场报价策略优化</li><li>电网故障自愈</li><li>虚拟电厂聚合调度</li></ul><p><strong>标的：</strong> 瓦特智能、清大科越、电享科技、浙达能源</p><h3 id="_4-4-液冷散热" tabindex="-1">4.4 液冷散热 <a class="header-anchor" href="#_4-4-液冷散热" aria-label="Permalink to &quot;4.4 液冷散热&quot;">​</a></h3><p><strong>逻辑：</strong> 散热占数据中心能耗 30-40%，液冷是降PUE的关键</p><p><strong>路线：</strong></p><ul><li>冷板式液冷（已商用，PUE&lt;1.2）</li><li>浸没式液冷（早期，PUE&lt;1.05，但维护复杂）</li></ul><p><strong>标的：</strong> 英维克、高澜股份、网宿科技（绿色云图）</p><h3 id="_4-5-虚拟电厂-vpp-聚合数据中心" tabindex="-1">4.5 虚拟电厂（VPP）聚合数据中心 <a class="header-anchor" href="#_4-5-虚拟电厂-vpp-聚合数据中心" aria-label="Permalink to &quot;4.5 虚拟电厂（VPP）聚合数据中心&quot;">​</a></h3><p><strong>逻辑：</strong> 把分散的数据中心聚合为虚拟电厂，统一参与电力市场</p><p><strong>壁垒：</strong></p><ul><li>聚合平台技术（实时调度+AI优化）</li><li>客户资源（签约数据中心数量）</li><li>电力市场交易资质</li></ul><h3 id="_4-6-低功耗算力芯片" tabindex="-1">4.6 低功耗算力芯片 <a class="header-anchor" href="#_4-6-低功耗算力芯片" aria-label="Permalink to &quot;4.6 低功耗算力芯片&quot;">​</a></h3><p><strong>逻辑：</strong> 同等算力下功耗更低→电费更少→PUE压力更小</p><p><strong>方向：</strong></p><ul><li>推理专用芯片（ASIC/NPU）</li><li>存算一体芯片（减少数据搬运功耗）</li><li>光子计算（长期）</li></ul><hr><h2 id="五、市场规模估算" tabindex="-1">五、市场规模估算 <a class="header-anchor" href="#五、市场规模估算" aria-label="Permalink to &quot;五、市场规模估算&quot;">​</a></h2><table tabindex="0"><thead><tr><th>细分领域</th><th>2026E</th><th>2030E</th><th>CAGR</th></tr></thead><tbody><tr><td>数据中心需求响应</td><td>5-10亿</td><td>50-100亿</td><td>60%+</td></tr><tr><td>算力调度平台</td><td>10-20亿</td><td>100-200亿</td><td>50%+</td></tr><tr><td>AI电力交易</td><td>2-5亿</td><td>30-50亿</td><td>70%+</td></tr><tr><td>液冷散热（数据中心）</td><td>50-80亿</td><td>300-500亿</td><td>45%+</td></tr><tr><td>VPP平台</td><td>20-30亿</td><td>100-200亿</td><td>40%+</td></tr><tr><td>低功耗算力芯片</td><td>20-50亿</td><td>200-500亿</td><td>60%+</td></tr></tbody></table><hr><h2 id="六、风险与挑战" tabindex="-1">六、风险与挑战 <a class="header-anchor" href="#六、风险与挑战" aria-label="Permalink to &quot;六、风险与挑战&quot;">​</a></h2><ol><li><strong>商业模式不成熟</strong> — 需求响应收益机制还在试点，谁出钱？</li><li><strong>政策不确定性</strong> — 电力市场化改革进度可能不及预期</li><li><strong>技术整合难度</strong> — IT 和 OT 的融合需要跨领域人才</li><li><strong>利益博弈</strong> — 电网、数据中心、政府三方博弈可能延缓落地</li><li><strong>资源限制</strong> — 西部算力中心的水资源、网络、人才配套不足</li></ol><hr><p><em>创建：2026-06-12 | 当前重点赛道</em></p>`,65)])])}const g=a(n,[["render",s]]);export{u as __pageData,g as default};
